import{_ as e,o as t,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-30.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-30.md"}'),n={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-30.md"};function s(l,r,i,h,c,d){return t(),a("div",null,[...r[0]||(r[0]=[o('<p>🫘 黃豆追蹤日報 — 2026年5月30日（週六）</p><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-05-30 05:00 = 2026-05-29 21:00 UTC) <strong>昨日敘事延續</strong>：美伊協議「largely negotiated」→ 油價從 $100+ 回落至 $87-92 → 化肥危機有望缓解但尚未確認 → 種植進度超前</p></blockquote><hr><h2 id="📊-8項指標檢查" tabindex="-1">📊 8項指標檢查 <a class="header-anchor" href="#📊-8項指標檢查" aria-label="Permalink to &quot;📊 8項指標檢查&quot;">​</a></h2><h3 id="指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-無新更新" tabindex="-1">指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（無新更新） <a class="header-anchor" href="#指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-無新更新" aria-label="Permalink to &quot;指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（無新更新）&quot;">​</a></h3><p>截至 5/24，美國黃豆種植完成度 <strong>79%</strong>（5年平均 53%）。Emergence 49%（5年平均 40%）。Illinois 84%、Iowa 90%。全線超前。本週無新報告（Memorial Day 延後），下一份預計 6/2 發布。</p><p><strong>與昨日比較</strong>：無變化。種植進度維持超前水平，但 Ohio 部分地區暴雨、Wisconsin/Michigan 種植延遲的區域風險仍在。</p><p>📎 來源：<a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a> · <a href="https://www.rfdtv.com/crop-progress-highlights-corn-and-soybean-planting-near-completion-as-winter-wheat-concerns-deepen" target="_blank" rel="noreferrer">RFDTV</a> （T: 05:00 TST）</p><hr><h3 id="指標2️⃣-巴西供應-—-🟢-持續擴張-無重大變化" tabindex="-1">指標2️⃣ 巴西供應 — 🟢 持續擴張（無重大變化） <a class="header-anchor" href="#指標2️⃣-巴西供應-—-🟢-持續擴張-無重大變化" aria-label="Permalink to &quot;指標2️⃣ 巴西供應 — 🟢 持續擴張（無重大變化）&quot;">​</a></h3><p>巴西收割順利，出口保持強勁。USDA 預測 2026-27 年度全球油籽產量增長。具體最新數據待 CONAB 月度報告。巴西豐收持續壓制國際價格上行空間，但荷莫茲封鎖推高替代航線運費。</p><p><strong>與昨日比較</strong>：無重大變化。</p><p>📎 來源：<a href="https://www.farmprogress.com/marketing/soybean-futures-surge-as-usda-forecasts-tighter-supplies" target="_blank" rel="noreferrer">Farm Progress</a> （T: 05:00 TST）</p><hr><h3 id="指標3️⃣-尿素價格-多單訊號-—-🔴-維持高檔-但若協議成立將缓解" tabindex="-1">指標3️⃣ 尿素價格 + 多單訊號 — 🔴 維持高檔（但若協議成立將缓解） <a class="header-anchor" href="#指標3️⃣-尿素價格-多單訊號-—-🔴-維持高檔-但若協議成立將缓解" aria-label="Permalink to &quot;指標3️⃣ 尿素價格 + 多單訊號 — 🔴 維持高檔（但若協議成立將缓解）&quot;">​</a></h3><p><strong>最新報價</strong>：</p><ul><li>埃及尿素：$940/噸（封鎖前約 $490，+92%）</li><li>美國墨西哥灣：$710/噸（2022年以來最高）</li><li>全球肥料價格指數：較去年 +30%，尿素 +60%，DAP +6%</li></ul><p><strong>關鍵變化</strong>：Trump 宣稱協議「largely negotiated」→ 若荷莫茲重開 → 尿素供應有望恢復 → 但尚未確認。市場目前維持觀望。</p><p><strong>與昨日比較</strong>：無實質變化。昨日 hopeful 情緒延續，但 Trump 未宣布最終決定 → 化肥危機緩解仍懸而未決。</p><p>📎 來源：<a href="https://blogs.worldbank.org/en/opendata/fertilizer-prices-surge-as-strait-of-hormuz-disruptions-tighten-" target="_blank" rel="noreferrer">World Bank</a> · <a href="https://www.foodingredientsfirst.com/news/strait-of-hormuz-fertilizer-crisis-food-prices.html" target="_blank" rel="noreferrer">Food Ingredients First</a> · <a href="https://www.farmprogress.com/business/farmers-turn-to-manure-urine-as-fertilizer-prices-surge" target="_blank" rel="noreferrer">Farm Progress</a> （T: 05:00 TST）</p><hr><h3 id="指標4️⃣-荷莫茲海峽通航狀態-—-🟡-從「希望」回到「不確定」" tabindex="-1">指標4️⃣ 荷莫茲海峽通航狀態 — 🟡 從「希望」回到「不確定」 <a class="header-anchor" href="#指標4️⃣-荷莫茲海峽通航狀態-—-🟡-從「希望」回到「不確定」" aria-label="Permalink to &quot;指標4️⃣ 荷莫茲海峽通航狀態 — 🟡 從「希望」回到「不確定」&quot;">​</a></h3><p><strong>5/29 最新</strong>：</p><ul><li><strong>Trump 宣稱</strong>：協議「largely negotiated」，荷莫茲將立即開放</li><li><strong>但</strong>：Iran IRGC 向 4 艘船隻射擊警告（未經協調通過）</li><li><strong>實際通航</strong>：維持低檔（~23 艘/日，戰前 125-140 艘/日）</li><li><strong>最新矛盾</strong>：Trump 說封鎖「will now be lifted」→ 但伊朗仍在射擊 → 誰說了算？</li></ul><p><strong>對黃豆影響</strong>：</p><ul><li>若協議成立 → 化肥供應恢復 + 運費正常化 → 黃豆成本壓力大減</li><li>若協議破裂 → 化肥危機延續 + 運費飆升 → 種植成本進一步上升</li><li><strong>當前狀態</strong>：懸而未決，市場在 hope 與 fear 間拉鋸</li></ul><p>📎 來源：<a href="https://www.bbc.com/news/articles/crmp121z3z8o" target="_blank" rel="noreferrer">BBC</a> · <a href="https://www.cnbc.com/2026/05/29/trump-iran-deal-hormuz-nuclear-war.html" target="_blank" rel="noreferrer">CNBC</a> · <a href="https://www.cnn.com/2026/05/29/world/live-news/iran-trump-war-news" target="_blank" rel="noreferrer">CNN</a> （T: 05:00 TST）</p><hr><h3 id="指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" tabindex="-1">指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展） <a class="header-anchor" href="#指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" aria-label="Permalink to &quot;指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展）&quot;">​</a></h3><ul><li>中國承諾 2026-28 年每年至少購買 2,500 萬噸美國黃豆</li><li>白宮 5/26 事實清單：中國將額外購買每年至少 $170 億美元美國農產品</li><li>2026年前兩個月美國對中黃豆出口 +79.66%</li><li><strong>但</strong>：2025年3月至2026年2月，美國對中農產品出口下降 $149 億（黃豆佔一半），為2007年以來最低</li><li><strong>新發展</strong>：Trump 政府維持對加拿大/墨西哥關稅，啟動 CUSMA 重新談判 → 貿易政策不確定性延續</li></ul><p>📎 來源：<a href="https://www.scmp.com/economy/global-economy/article/3353803/soybean-counters-scope-china-us-farm-deal-depends-math-analysts-say" target="_blank" rel="noreferrer">SCMP</a> · <a href="https://hpj.com/2026/05/22/china-commits-to-additional-purchases-of-u-s-ag-products/" target="_blank" rel="noreferrer">HPJ</a> · <a href="https://www.forbes.com/sites/kenroberts/2026/04/24/us-soybean-exports-in-2026-show-27-increase-after-abysmal-2025/" target="_blank" rel="noreferrer">Forbes</a> （T: 05:00 TST）</p><hr><h3 id="指標6️⃣-天然氣價格-—-🟢-微跌但穩定" tabindex="-1">指標6️⃣ 天然氣價格 — 🟢 微跌但穩定 <a class="header-anchor" href="#指標6️⃣-天然氣價格-—-🟢-微跌但穩定" aria-label="Permalink to &quot;指標6️⃣ 天然氣價格 — 🟢 微跌但穩定&quot;">​</a></h3><ul><li>Henry Hub 現貨：~$3.28/MMBtu（-0.01%）</li><li>FT Markets 報導：$3.32/MMBtu (+0.97%)</li><li>價格穩定，未見異常波動。天然氣是氮肥生產原料，但目前影響有限。</li></ul><p><strong>與昨日比較</strong>：無變化。</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://markets.ft.com/data/commodities/brent-crude-oil" target="_blank" rel="noreferrer">FT Markets</a> （T: 05:00 TST）</p><hr><h3 id="指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-超級聖嬰預警持續" tabindex="-1">指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 超級聖嬰預警持續 <a class="header-anchor" href="#指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-超級聖嬰預警持續" aria-label="Permalink to &quot;指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 超級聖嬰預警持續&quot;">​</a></h3><p><strong>最新更新</strong>：全球氣候正從拉尼娜過渡至強聖嬰事件（Super El Niño），預計北半球夏季形成，持續至年底。</p><ul><li><strong>對黃豆影響</strong>：歷史數據顯示聖嬰對全球黃豆單產正面影響 +2%~5%（美國/巴西為主）</li><li><strong>風險</strong>：強聖嬰可能導致南巴西南部洪水 + 巴西北部/東北部乾旱</li><li><strong>2015-16 超級聖嬰</strong>：巴西整體糧食產量 -9.5%</li><li><strong>美國區域風險</strong>：Ohio 暴雨受災、Wisconsin/Michigan 種植延遲</li></ul><p><strong>與昨日比較</strong>：無變化。聖嬰預警持續，需密切關注 6-8 月發展。</p><p>📎 來源：<a href="https://wmo.int/resources/publication-series/el-ninola-nina-updates/el-ninola-nina-update-february-2026" target="_blank" rel="noreferrer">WMO</a> · <a href="https://hectar.global/insights/article/el-nino-la-nina-agriculture-how-enso-cycles-reshape-crop-yields-and-commodity-prices-across-5-key-regions" target="_blank" rel="noreferrer">Hectar Global</a> · <a href="https://badgercropnetwork.com/soybean-yield-and-the-2026-super-el-nino-what-growers-need-to-know/" target="_blank" rel="noreferrer">Badger Crop Network</a> （T: 05:00 TST）</p><hr><h3 id="指標8️⃣-cbot-黃豆期貨價格區間-—-🟡-小幅回落但仍穩健" tabindex="-1">指標8️⃣ CBOT 黃豆期貨價格區間 — 🟡 小幅回落但仍穩健 <a class="header-anchor" href="#指標8️⃣-cbot-黃豆期貨價格區間-—-🟡-小幅回落但仍穩健" aria-label="Permalink to &quot;指標8️⃣ CBOT 黃豆期貨價格區間 — 🟡 小幅回落但仍穩健&quot;">​</a></h3><p><strong>最新報價</strong>：</p><ul><li>CBOT 7月黃豆（ZSN26）：~1,186.25 ¢/bu（+0.02%），前收 1,186.00</li><li>TradingEconomics：1,196.84 ¢/bu (+0.20%)</li><li>5月合約（ZSK26）：已到期，~1,174.50 ¢/bu（-40.75）</li><li>30日區間：1,099.25 - 1,235.00 ¢/bu</li><li><strong>Barchart 5/29 午盤</strong>：黃豆下跌 5-10 cents，未能突破 $12</li><li><strong>現貨</strong>：cmdtyView 全國均價 $11.25¾（+9½ cents）</li><li><strong>USDA 出口銷售</strong>：舊作 299,899 MT（符合預期）、新作 137,708 MT（符合預期）</li><li><strong>私人出口 sale</strong>：192,000 MT 至未知目的地（60K 舊作 + 132K 新作）</li></ul><p><strong>注意</strong>：05:00 TST = 17:00 ET，CME 黃豆期貨處於 14:00-20:00 ET 休息時段，此為 5/29 盤中數據</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://farmbucks.com/futures/grain-oilseeds/soybeans" target="_blank" rel="noreferrer">Farmbucks</a> · <a href="https://www.barchart.com/futures/quotes/zs*0/futures-prices" target="_blank" rel="noreferrer">Barchart</a> · <a href="https://www.investing.com/commodities/us-soybeans-historical-data" target="_blank" rel="noreferrer">Investing.com</a> （T: 05:00 TST）</p><hr><h2 id="📰-黃豆即時新聞-5-則" tabindex="-1">📰 黃豆即時新聞 5 則 <a class="header-anchor" href="#📰-黃豆即時新聞-5-則" aria-label="Permalink to &quot;📰 黃豆即時新聞 5 則&quot;">​</a></h2><ol><li><p><strong>[5/29] Trump 美伊協議「largely negotiated」— 荷莫茲有望重開</strong> Trump listed conditions: no nuclear weapons, Hormuz immediately open, no tolls, mines removed within 30 days, US blockade &quot;will be lifted.&quot; But ended Situation Room meeting without &quot;final determination.&quot; 📎 <a href="https://www.bbc.com/news/articles/crmp121z3z8o" target="_blank" rel="noreferrer">BBC</a> · <a href="https://www.cnbc.com/2026/05/29/trump-iran-deal-hormuz-nuclear-war.html" target="_blank" rel="noreferrer">CNBC</a></p></li><li><p><strong>[5/29] CBOT 農產品回落：黃豆 -5-10 cents、原油壓力</strong> Soybeans trading with 5-10 cent losses as nearbys fail to breach $12. Crude oil down $2.08/bbl pressuring the complex. Money flowing out ahead of weekend. 📎 <a href="https://www.barchart.com/futures/quotes/zs*0/futures-prices" target="_blank" rel="noreferrer">Barchart</a></p></li><li><p><strong>[5/29] USDA 出口銷售：舊作 299,899 MT、新作 137,708 MT</strong> Total old crop bean sales during week of May 21 in the middle of estimates. New crop business also in line. Export commitments now at 39.371 MMT, 18% decline from last year. 📎 <a href="https://www.barchart.com/futures/quotes/zs*0/futures-prices" target="_blank" rel="noreferrer">Barchart</a></p></li><li><p><strong>[5/29] 私人出口 sale 192,000 MT 至未知目的地</strong> USDA reported a private export sale of 192,000 MT soybeans to unknown destinations, with 60,000 MT old crop and 132,000 MT new crop. 📎 <a href="https://www.barchart.com/futures/quotes/zs*0/futures-prices" target="_blank" rel="noreferrer">Barchart</a></p></li><li><p><strong>[5/29] 油價回落至 $87-92 — 協議希望 vs 實際衝突</strong> WTI fell to $87.67, Brent to $90.36. But Iran IRGC fired warning shots at 4 vessels near Hormuz, casting doubt on deal implementation. 📎 <a href="https://markets.ft.com/data/commodities/brent-crude-oil" target="_blank" rel="noreferrer">FT Markets</a> · <a href="https://www.cnn.com/2026/05/29/world/live-news/iran-trump-war-news" target="_blank" rel="noreferrer">CNN</a></p></li></ol><hr><h2 id="🔮-情景分析" tabindex="-1">🔮 情景分析 <a class="header-anchor" href="#🔮-情景分析" aria-label="Permalink to &quot;🔮 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>黃豆價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>美伊協議成立 + 荷莫茲重開</td><td>35%</td><td>-5~10%</td><td>化肥供應恢復 + 運費正常化 + 油價下跌</td></tr><tr><td>協議延後（雙方拉鋸）</td><td>35%</td><td>+0~3%</td><td>化肥成本維持高檔，種植進度超前部分抵消</td></tr><tr><td>協議破裂 + 衝突升級</td><td>20%</td><td>+10~15%</td><td>化肥斷供 + 運費飆升 + 油價再漲</td></tr><tr><td>超級聖嬰 + 化肥危機雙重夾擊</td><td>10%</td><td>+15~25%</td><td>全球糧食危機、生物燃料需求激增</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-29): Soybeans 1,196.84 ¢/bu</li><li>Farmbucks (2026-05-29): CBOT ZSN26 1,186.25 ¢/bu</li><li>Barchart (2026-05-29): Soybeans 5-10 cent losses, Cash $11.25¾</li><li>Investing.com (2026-05-29): US Soybeans 1,196.50 (+0.19%)</li><li>BBC/CNBC/CNN (2026-05-29): Trump Iran deal status</li><li>World Bank (2026-05): Fertilizer prices surge +30-60%</li><li>SCMP/HPJ (2026-05): China-US soybean trade commitments</li><li>WMO/NOAA (2026): El Niño forecast – Super El Niño likely</li><li>DTN/PF (2026-05-26): USDA Crop Progress – Soybeans 79%</li><li>FT Markets (2026-05-29): WTI $87.67, Natural Gas $3.32</li></ol>',57)])])}const u=e(n,[["render",s]]);export{g as __pageData,u as default};
